import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import Login from './pages/Login';
import Home from './pages/Home';
import PatientDashboard from './pages/PatientDashboard';
import Appointments from './pages/Appointments';
import Queue from './pages/Queue';
import Triage from './pages/Triage';
import Consultation from './pages/Consultation';
import Prescriptions from './pages/Prescriptions';
import LabTests from './pages/LabTests';
import auth from './services/auth';

function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const currentUser = auth.getCurrentUser();
    if (currentUser) {
      setUser(currentUser);
    }
    setLoading(false);
  }, []);

  const handleLogout = () => {
    auth.logout();
    setUser(null);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-4 border-blue-500 mx-auto mb-4"></div>
          <p className="text-xl text-gray-700 font-semibold">Loading Clinic Management System...</p>
        </div>
      </div>
    );
  }

  if (!user) {
    return <Login onLogin={setUser} />;
  }

  return (
    <Router>
      <div className="flex h-screen bg-gray-50">
        <Sidebar userRole={user.role} />
        <div className="flex-1 flex flex-col overflow-hidden">
          <Header user={user} onLogout={handleLogout} />
          <main className="flex-1 overflow-auto bg-gray-50">
            <Routes>
              <Route path="/dashboard" element={<Dashboard userRole={user.role} />} />
              <Route path="/appointments" element={<Appointments userRole={user.role} />} />
              <Route path="/queue" element={<Queue userRole={user.role} />} />
              <Route path="/triage" element={<Triage userRole={user.role} />} />
              <Route path="/consultation" element={<Consultation userRole={user.role} />} />
              <Route path="/prescriptions" element={<Prescriptions userRole={user.role} />} />
              <Route path="/lab-orders" element={<LabTests userRole={user.role} />} />
              <Route path="/" element={<Navigate to="/dashboard" />} />
            </Routes>
          </main>
        </div>
      </div>
    </Router>
  );
}

export default App;
